import app from 'flarum/common/app';
function base() {
  return app.forum.attribute('apiUrl') + '/projects';
}

/** Admin-defined building blocks shipped in the forum boot payload. */
export function config() {
  return app.forum.attribute('projectsConfig') || {
    categories: [],
    fields: [],
    buttons: []
  };
}
export function listProjects(params) {
  if (params === void 0) {
    params = {};
  }
  return app.request({
    method: 'GET',
    url: base(),
    params
  });
}
export function getProject(idOrSlug) {
  return app.request({
    method: 'GET',
    url: "".concat(base(), "/").concat(idOrSlug)
  });
}
export function saveProject(attributes, id) {
  return app.request({
    method: id ? 'PATCH' : 'POST',
    url: id ? "".concat(base(), "/").concat(id) : base(),
    body: {
      data: {
        attributes
      }
    }
  });
}
export function deleteProject(id) {
  return app.request({
    method: 'DELETE',
    url: "".concat(base(), "/").concat(id)
  });
}
export function likeProject(id) {
  return app.request({
    method: 'POST',
    url: "".concat(base(), "/").concat(id, "/like")
  });
}
export function moderateProject(id, action, reason) {
  return app.request({
    method: 'POST',
    url: "".concat(base(), "/").concat(id, "/moderate"),
    body: {
      data: {
        attributes: {
          action,
          reason
        }
      }
    }
  });
}

/** Upload a project image; resolves to its public URL. */
export function uploadImage(file) {
  const body = new FormData();
  body.append('image', file);
  return app.request({
    method: 'POST',
    url: "".concat(base(), "/upload-image"),
    serialize: raw => raw,
    // send the FormData untouched
    body
  }).then(res => res.data.url);
}

// ---- Admin: definition management ----------------------------------------

export function getConfig() {
  return app.request({
    method: 'GET',
    url: "".concat(base(), "/config")
  });
}
function saveDefinition(kind, attributes, id) {
  return app.request({
    method: id ? 'PATCH' : 'POST',
    url: id ? "".concat(base(), "/config/").concat(kind, "/").concat(id) : "".concat(base(), "/config/").concat(kind),
    body: {
      data: {
        attributes
      }
    }
  });
}
function deleteDefinition(kind, id) {
  return app.request({
    method: 'DELETE',
    url: "".concat(base(), "/config/").concat(kind, "/").concat(id)
  });
}
export const saveCategory = (a, id) => saveDefinition('categories', a, id);
export const deleteCategory = id => deleteDefinition('categories', id);
export const saveField = (a, id) => saveDefinition('fields', a, id);
export const deleteField = id => deleteDefinition('fields', id);
export const saveButton = (a, id) => saveDefinition('buttons', a, id);
export const deleteButton = id => deleteDefinition('buttons', id);
flarum.reg.add('ernestdefoe-projects', 'common/api', { config: config,listProjects: listProjects,getProject: getProject,saveProject: saveProject,deleteProject: deleteProject,likeProject: likeProject,moderateProject: moderateProject,uploadImage: uploadImage,getConfig: getConfig,saveCategory: saveCategory,deleteCategory: deleteCategory,saveField: saveField,deleteField: deleteField,saveButton: saveButton,deleteButton: deleteButton, });